import Sidebar from '../components/Sidebar';
import startImage from '../assets/mainpage.png';

function NewsPage() {
  return (
    <div className="relative w-full min-h-screen bg-white overflow-hidden">
      {/* 흐릿한 배경 이미지 */}
      <img
        src={startImage}
        alt="배경"
        className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[80%] h-[80%]  object-cover"
      />

      {/* 레이아웃: 사이드바 + 메인 */}
      <div className="relative z-10 flex px-8 pt-12 items-start">
        {/* Sidebar */}
        <Sidebar />

        {/* 메인 콘텐츠 */}
        <main className="flex-1 px-8 overflow-hidden h-[90vh]">
          {/* 청약 정보 */}
          <section className="mt-4 mb-6">
            <h2 className="text-2xl font-bold text-gray-800 mb-6">청약 정보</h2>
            <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
              {[
                { name: 'LH 청약 정보', logo: 'LH 청약+' },
                { name: 'SH 청약 정보', logo: 'SH 서울주택도시공사' },
                { name: 'GH 청약 정보', logo: 'GH 주택청약센터' },
              ].map((item, idx) => (
                <div
                  key={idx}
                  className="bg-white border border-blue-300 rounded-xl p-4 flex flex-col items-center text-center shadow hover:shadow-md transition"
                >
                  <div className="text-blue-600 font-bold text-xl mb-2">{item.logo}</div>
                  <div className="text-sm text-gray-700">{item.name}</div>
                </div>
              ))}
            </div>
          </section>

          {/* 최신 뉴스 */}
          <section>
            <h2 className="text-2xl font-bold text-gray-800 mb-6">최신 뉴스</h2>
            <div className="grid grid-cols-2 md:grid-cols-3 gap-6">
              {[1, 2, 3, 4, 5, 6].map((i) => (
                <div key={i} className="flex flex-col items-center">
                  <div className="w-full aspect-[4/3] bg-blue-500 text-white rounded-xl flex items-center justify-center shadow">
                    뉴스 썸네일
                  </div>
                  <p className="mt-2 text-sm text-gray-800 font-medium">뉴스 제목 {i}</p>
                </div>
              ))}
            </div>
          </section>
        </main>
      </div>
    </div>
  );
}

export default NewsPage;
